using UnityEngine;

/// <summary>
/// Contrato comum a todas as secções do Menu de Pausa (Área Atual, Diário,
/// Formas, Itens e Instintos, Progresso, Opções — Tarefas #7-12).
///
/// O <see cref="PauseMenuController"/> mantém uma lista ordenada destas
/// secções (uma por "página"), activa apenas a seleccionada e chama
/// <see cref="Refresh"/> sempre que o menu abre ou o jogador navega para essa
/// secção (L/R). Cada implementação deve popular o seu próprio conteúdo a
/// partir de PlayerProgress/WorldState/AreaData, etc.
/// </summary>
public interface IPauseMenuSection
{
    /// <summary>Nome da secção mostrado na barra de navegação (ex: "ÁREA", "DIÁRIO").</summary>
    string SectionName { get; }

    /// <summary>GameObject raiz da secção — activado quando seleccionada, desactivado nas restantes.</summary>
    GameObject Root { get; }

    /// <summary>
    /// Chamado sempre que a secção passa a estar visível (abertura do menu ou
    /// navegação L/R até ela). Deve repopular o conteúdo a partir do estado
    /// actual do jogo.
    /// </summary>
    void Refresh();

    /// <summary>Chamado quando a secção deixa de estar visível (navegação para outra secção, ou fecho do menu).</summary>
    void OnHide();
}
